    /**
     * Builds a detailed validation error with BadRequest field violations.
     */
    private StatusRuntimeException buildDetailedValidationError(
            IllegalArgumentException exception,
            String methodName,
            String requestPayload) {

        String fullStackTrace = getFullStackTrace(exception);
        String timestamp = Instant.now().toString();

        Status.Builder statusBuilder = Status.newBuilder()
                .setCode(io.grpc.Status.INVALID_ARGUMENT.getCode().value())
                .setMessage("Validation failed in " + methodName + ": " + exception.getMessage() +
                        " | Full request payload: " + requestPayload +
                        " | Timestamp: " + timestamp);

        // Add DebugInfo
        DebugInfo debugInfo = DebugInfo.newBuilder()
                .addAllStackEntries(java.util.Arrays.asList(fullStackTrace.split("\n")))
                .setDetail("Validation error in " + methodName + ". Input validation failed. " +
                        "Request payload dumped for debugging: " + requestPayload)
                .build();
        statusBuilder.addDetails(Any.pack(debugInfo));

        // Add BadRequest details
        BadRequest.FieldViolation fieldViolation = BadRequest.FieldViolation.newBuilder()
                .setField(methodName + ".request")
                .setDescription(exception.getMessage() + " | Raw request: " + requestPayload)
                .build();

        BadRequest badRequest = BadRequest.newBuilder()
                .addFieldViolations(fieldViolation)
                .build();
        statusBuilder.addDetails(Any.pack(badRequest));

        // Add ErrorInfo with internal state
        Map<String, String> metadata = new HashMap<>(buildInternalStateSnapshot());
        metadata.put("method", methodName);
        metadata.put("request_payload", requestPayload);
        metadata.put("timestamp", timestamp);
        metadata.put("exception_message", exception.getMessage());

        ErrorInfo errorInfo = ErrorInfo.newBuilder()
                .setReason("VALIDATION_FAILURE")
                .setDomain("com.example.debug")
                .putAllMetadata(metadata)
                .build();
        statusBuilder.addDetails(Any.pack(errorInfo));

        return StatusProto.toStatusRuntimeException(statusBuilder.build());
    }

    private String getFullStackTrace(Throwable throwable) {
        StringWriter sw = new StringWriter();
        PrintWriter pw = new PrintWriter(sw);
        throwable.printStackTrace(pw);
        
        // Also include cause chain
        Throwable cause = throwable.getCause();
        while (cause != null) {
            pw.println("--- Caused by ---");
            cause.printStackTrace(pw);
            cause = cause.getCause();
        }
        
        pw.flush();
        return sw.toString();
    }

    private Throwable getRootCause(Throwable throwable) {
        Throwable cause = throwable;
        while (cause.getCause() != null) {
            cause = cause.getCause();
        }
        return cause;
    }

    private String getServerHost() {
        try {
            return InetAddress.getLocalHost().getHostName() + "/" + InetAddress.getLocalHost().getHostAddress();
        } catch (Exception e) {
            return "unknown-host";
        }
    }

    private Map<String, String> buildInternalStateSnapshot() {
        return new HashMap<>(internalStateStore);
    }

    private DatabaseErrorDetails buildDatabaseErrorDetails(SQLException e) {
        DatabaseErrorDetails details = new DatabaseErrorDetails();
        details.errorCode = e.getErrorCode();
        details.sqlState = e.getSQLState();
        details.message = e.getMessage();
        details.driverInfo = "PostgreSQL JDBC Driver 42.6.0";
        details.connectionUrl = "jdbc:postgresql://db-primary.internal:5432/production_db";
        
        // Include chained SQL exceptions
        StringBuilder chainedErrors = new StringBuilder();
        SQLException next = e.getNextException();
        while (next != null) {
            chainedErrors.append("Chained: [").append(next.getErrorCode()).append("] ")
                    .append(next.getMessage()).append("; ");
            next = next.getNextException();
        }
        if (chainedErrors.length() > 0) {
            details.message += " | Chained exceptions: " + chainedErrors.toString();
        }
        
        return details;
    }

    // Inner class to hold database error details
    private static class DatabaseErrorDetails {
        int errorCode;
        String sqlState;
        String message;
        String driverInfo;
        String connectionUrl;
    }

    // Custom exception
    private static class UserNotFoundException extends Exception {
        public UserNotFoundException(String message) {
            super(message);
        }
    }
