package com.example.debug.server;

import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * Simulates database operations that can throw various exceptions
 * to demonstrate detailed error reporting.
 */
public class DatabaseSimulator {

    public Map<String, String> findUser(String userId) throws Exception {
        // Simulate various failure scenarios
        if ("error_timeout".equals(userId)) {
            SQLException cause = new SQLException(
                    "Connection timed out after 30000ms to db-primary.internal:5432. " +
                    "Pool stats: active=15, idle=0, waiting=23. " +
                    "Last successful connection: 2024-01-15T10:30:00Z",
                    "08001", 0);
            throw new RuntimeException("Database connection pool exhausted while looking up user: " + userId, cause);
        }

        if ("error_constraint".equals(userId)) {
            throw new SQLException(
                    "ERROR: duplicate key value violates unique constraint \"users_email_key\". " +
                    "Detail: Key (email)=(duplicate@example.com) already exists. " +
                    "Table: public.users, Schema: public, Constraint: users_email_key",
                    "23505", 23505);
        }

        if ("error_deadlock".equals(userId)) {
            SQLException deadlock = new SQLException(
                    "ERROR: deadlock detected. " +
                    "Detail: Process 12345 waits for ShareLock on transaction 67890; " +
                    "blocked by process 11111. Process 11111 waits for ShareLock on transaction 12345; " +
                    "blocked by process 12345. " +
                    "Hint: See server log for query details. " +
                    "Context: while updating tuple (0,5) in relation \"users\"",
                    "40P01", 40001);
            deadlock.setNextException(new SQLException(
                    "Automatic retry failed after 3 attempts. Last retry at 2024-01-15T10:35:22Z",
                    "40P01", 40001));
            throw deadlock;
        }

        // Simulate a found user
        if ("user123".equals(userId)) {
            Map<String, String> user = new HashMap<>();
            user.put("name", "John Doe");
            user.put("email", "john@example.com");
            return user;
        }

        // User not found
        return null;
    }

    public void updateRecord(String recordId, String data) throws SQLException {
        if ("readonly_record".equals(recordId)) {
            throw new SQLException(
                    "ERROR: cannot execute UPDATE in a read-only transaction. " +
                    "Server is in hot standby mode. " +
                    "Connection routed to: db-replica-02.internal:5432. " +
                    "Expected target: db-primary.internal:5432. " +
                    "DNS resolution may be stale.",
                    "25006", 25006);
        }

        if ("large_record".equals(recordId)) {
            throw new SQLException(
                    "ERROR: value too long for type character varying(255). " +
                    "Attempted to insert " + data.length() + " characters. " +
                    "Column: records.data, Table: public.records, Schema: public. " +
                    "Current column definition: VARCHAR(255)",
                    "22001", 22001);
        }

        if ("locked_record".equals(recordId)) {
            SQLException lockTimeout = new SQLException(
                    "ERROR: canceling statement due to lock timeout. " +
                    "Lock wait timeout exceeded (lock_timeout=5000ms). " +
                    "Waiting for RowExclusiveLock on relation 16385 of database 16384. " +
                    "Blocked by PID 9999 running: UPDATE records SET data='...' WHERE id='locked_record'",
                    "55P03", 55003);
            throw lockTimeout;
        }
    }

    public List<String> executeQuery(String sqlQuery) throws SQLException {
        if (sqlQuery == null || sqlQuery.trim().isEmpty()) {
            throw new SQLException(
                    "ERROR: syntax error at or near \"\". " +
                    "Empty query string received. " +
                    "Query planning failed at parse stage.",
                    "42601", 42601);
        }

        if (sqlQuery.toLowerCase().contains("drop") || sqlQuery.toLowerCase().contains("delete")) {
            throw new SQLException(
                    "ERROR: permission denied for table. " +
                    "User 'app_readonly' does not have DELETE/DROP privilege on relation. " +
                    "Attempted query: " + sqlQuery + ". " +
                    "Current role: app_readonly. Required role: app_admin. " +
                    "Grant statement needed: GRANT DELETE ON TABLE ... TO app_readonly",
                    "42501", 42501);
        }

        if (sqlQuery.toLowerCase().contains("select")) {
            return Arrays.asList(
                    "row1: {id=1, name=test1}",
                    "row2: {id=2, name=test2}"
            );
        }

        throw new SQLException(
                "ERROR: unrecognized query type. " +
                "Query: " + sqlQuery + ". " +
                "Supported operations: SELECT. " +
                "This service uses a read-only connection pool.",
                "42000", 42000);
    }
}


