package com.example.debug.server;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.ServerInterceptor;
import io.grpc.ServerCall;
import io.grpc.ServerCallHandler;
import io.grpc.Metadata;
import io.grpc.ForwardingServerCall.SimpleForwardingServerCall;
import io.grpc.ForwardingServerCallListener.SimpleForwardingServerCallListener;

import java.io.IOException;
import java.time.Instant;
import java.util.logging.Level;
import java.util.logging.Logger;

public class DebugGrpcServer {

    private static final Logger logger = Logger.getLogger(DebugGrpcServer.class.getName());
    private Server server;
    private final int port;

    public DebugGrpcServer(int port) {
        this.port = port;
    }

    public void start() throws IOException {
        server = ServerBuilder.forPort(port)
                .addService(new DebugServiceImpl())
                .intercept(new DetailedLoggingInterceptor())
                .build()
                .start();

        logger.info("Debug gRPC Server started on port " + port);

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server...");
            DebugGrpcServer.this.stop();
            logger.info("Server shut down.");
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    /**
     * Server interceptor that logs all requests and responses with full details,
     * and adds server-side metadata to error responses for debugging.
     */
    private static class DetailedLoggingInterceptor implements ServerInterceptor {
        
        @Override
        public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
                ServerCall<ReqT, RespT> call,
                Metadata headers,
                ServerCallHandler<ReqT, RespT> next) {

            String methodName = call.getMethodDescriptor().getFullMethodName();
            String callId = java.util.UUID.randomUUID().toString();
            long startTime = System.nanoTime();

            logger.info(String.format("[%s] Incoming call: %s | Headers: %s | Timestamp: %s",
                    callId, methodName, headers.toString(), Instant.now()));

            ServerCall<ReqT, RespT> wrappedCall = new SimpleForwardingServerCall<ReqT, RespT>(call) {
                @Override
                public void close(io.grpc.Status status, Metadata trailers) {
                    long duration = (System.nanoTime() - startTime) / 1_000_000;
                    
                    if (!status.isOk()) {
                        // Add debugging metadata to error trailers
                        Metadata.Key<String> callIdKey = Metadata.Key.of("x-debug-call-id", Metadata.ASCII_STRING_MARSHALLER);
                        Metadata.Key<String> durationKey = Metadata.Key.of("x-debug-duration-ms", Metadata.ASCII_STRING_MARSHALLER);
                        Metadata.Key<String> methodKey = Metadata.Key.of("x-debug-method", Metadata.ASCII_STRING_MARSHALLER);
                        Metadata.Key<String> timestampKey = Metadata.Key.of("x-debug-timestamp", Metadata.ASCII_STRING_MARSHALLER);
                        Metadata.Key<String> serverKey = Metadata.Key.of("x-debug-server-thread", Metadata.ASCII_STRING_MARSHALLER);

                        trailers.put(callIdKey, callId);
                        trailers.put(durationKey, String.valueOf(duration));
                        trailers.put(methodKey, methodName);
                        trailers.put(timestampKey, Instant.now().toString());
                        trailers.put(serverKey, Thread.currentThread().getName());

                        logger.log(Level.SEVERE, String.format(
                                "[%s] ERROR response for %s | Status: %s | Description: %s | Duration: %dms | Cause: %s",
                                callId, methodName, status.getCode(), status.getDescription(),
                                duration, status.getCause() != null ? status.getCause().toString() : "none"));
                    } else {
                        logger.info(String.format("[%s] SUCCESS response for %s | Duration: %dms",
                                callId, methodName, duration));
                    }

                    super.close(status, trailers);
                }
            };

            ServerCall.Listener<ReqT> listener = next.startCall(wrappedCall, headers);

            return new SimpleForwardingServerCallListener<ReqT>(listener) {
                @Override
                public void onMessage(ReqT message) {
                    logger.info(String.format("[%s] Request message for %s: %s",
                            callId, methodName, message.toString()));
                    super.onMessage(message);
                }

                @Override
                public void onHalfClose() {
                    try {
                        super.onHalfClose();
                    } catch (Exception e) {
                        logger.log(Level.SEVERE, String.format(
                                "[%s] Unhandled exception in %s: %s",
                                callId, methodName, e.toString()), e);
                        throw e;
                    }
                }
            };
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        int port = 50051;
        if (args.length > 0) {
            port = Integer.parseInt(args[0]);
        }

        final DebugGrpcServer server = new DebugGrpcServer(port);
        server.start();
        server.blockUntilShutdown();
    }
}


